public class DataProcessor
{
    public event Action<string, string> DataChanged;
    public event Action<string> ValidationFailed;
    public event Action ProcessCompleted;

    private string _data;
    private bool _isProcessing;

    public string Data
    {
        get { return _data; }
        set
        {
            string oldValue = _data;

            if (ValidateData(value))
            {
                _data = value;
                DataChanged?.Invoke(oldValue, value);
            }
            else
            {
                ValidationFailed?.Invoke("Invalid data format");
            }
        }
    }

    private bool ValidateData(string data)
    {
        return !string.IsNullOrEmpty(data) && data.Length <= 100;
    }

    public async Task ProcessDataAsync()
    {
        if (!_isProcessing)
        {
            _isProcessing = true;
            // Processing logic here
            await Task.Delay(100); // Replace DoEvents
            _isProcessing = false;
            ProcessCompleted?.Invoke();
        }
    }
}

