data_access_class.csharp_equivalent:
using System.Data;
using System.Data.SqlClient;

public class DataAccessLayer : IDisposable
{
    private SqlConnection _connection;
    private string _connectionString;
    private bool _disposed = false;

    public string ConnectionString
    {
        get { return _connectionString; }
        set { _connectionString = value; }
    }

    public bool Connect()
    {
        try
        {
            _connection = new SqlConnection(_connectionString);
            _connection.Open();
            return true;
        }
        catch
        {
            return false;
        }
    }

    public async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(string sql)
    {
        var results = new List<Dictionary<string, object>>();

        try
        {
            using (var command = new SqlCommand(sql, _connection))
            using (var reader = await command.ExecuteReaderAsync())
            {
                while (await reader.ReadAsync())
                {
                    var record = new Dictionary<string, object>();

                    for (int i = 0; i < reader.FieldCount; i++)
                    {
                        record[reader.GetName(i)] = reader.GetValue(i) ?? DBNull.Value;
                    }

                    results.Add(record);
                }
            }
        }
        catch (Exception ex)
        {
            throw new DataException($"Query execution failed: {ex.Message}", ex);
        }

        return results;
    }

    // Strongly-typed version
    public async Task<List<T>> ExecuteQueryAsync<T>(string sql, Func<IDataReader, T> mapper)
    {
        var results = new List<T>();

        using (var command = new SqlCommand(sql, _connection))
        using (var reader = await command.ExecuteReaderAsync())
        {
            while (await reader.ReadAsync())
            {
                results.Add(mapper(reader));
            }
        }

        return results;
    }

    public void Dispose()
    {
        Dispose(true);
        GC.SuppressFinalize(this);
    }

    protected virtual void Dispose(bool disposing)
    {
        if (!_disposed && disposing)
        {
            _connection?.Close();
            _connection?.Dispose();
            _disposed = true;
        }
    }
}

singleton_pattern.csharp_equivalent:
public sealed class Logger
{
    private static readonly Lazy<Logger> _instance = new Lazy<Logger>(() => new Logger());
    private readonly string _logFile;
    private readonly object _lockObject = new object();

    private Logger()
    {
        _logFile = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "log.txt");
    }

    public static Logger Instance => _instance.Value;

    public void WriteLog(string message)
    {
        lock (_lockObject)
        {
            try
            {
                using (var writer = new StreamWriter(_logFile, true))
                {
                    writer.WriteLine($"{DateTime.Now}: {message}");
                }
            }
            catch (Exception ex)
            {
                // Handle logging errors appropriately
                System.Diagnostics.Debug.WriteLine($"Logging failed: {ex.Message}");
            }
        }
    }

    public async Task WriteLogAsync(string message)
    {
        try
        {
            using (var writer = new StreamWriter(_logFile, true))
            {
                await writer.WriteLineAsync($"{DateTime.Now}: {message}");
            }
        }
        catch (Exception ex)
        {
            System.Diagnostics.Debug.WriteLine($"Async logging failed: {ex.Message}");
        }
    }
}

